    capturedOnDragEnd({ active: { id: 'c3' }, over: { id: 'c1' } })
    expect(DEFAULT_STATE.moveCard).toHaveBeenCalledWith('c3', 'ready', 0.5)
  })

  it('cross-column move appends to non-empty column when dropped on column header', () => {
